@@ -766,7 +766,17 @@ fn inferBinOpWithInferrer(
     // E.g., Rat.__truediv__ returns Rat, not float - must be handled before trait
     if (left_tag == .class_instance or right_tag == .class_instance) {
         if (binop.op == .Add or binop.op == .Sub or binop.op == .Mult or binop.op == .Div) {
-            return .unknown; // Class dunder method - type determined by method return
+            // If both operands are the SAME class type, assume result is also that class
+            // This handles common patterns like: Rat + Rat -> Rat
+            if (left_tag == .class_instance and right_tag == .class_instance) {
+                const left_class = left_type.class_instance;
+                const right_class = right_type.class_instance;
+                if (std.mem.eql(u8, left_class, right_class)) {
+                    return left_type; // Same class, return same type
+                }
+            }
+            // Mixed class types or class + primitive: fall back to unknown
+            return .unknown;
         }
     }

@@ -1054,6 +1054,23 @@ pub fn generate(self: *NativeCodegen, module: ast.Node.Module) ![]const u8 {
                         // Default - fall through to nativeTypeToZigType
                     }
                 }
+
+                // Check if this is a class instance for a known module-level class
+                // If so, use the class name directly instead of *runtime.PyObject
+                // This avoids type mismatch when assigning Class.init() to the variable
+                if (vt == .class_instance) {
+                    const class_name = vt.class_instance;
+                    // Check if this class is defined at module level in this file
+                    if (self.class_registry.classes.contains(class_name)) {
+                        break :blk class_name;
+                    }
+                    // Also check if it's registered as a module-level function (class constructors
+                    // are registered there during PHASE 2.1)
+                    if (self.module_level_funcs.contains(class_name)) {
+                        break :blk class_name;
+                    }
+                }
+
                 needs_free = true;
                 break :blk try self.nativeTypeToZigType(vt);
             } else "i64";
